<?phpnamespace App\Http\Resources;use Illuminate\Http\Request;use Illuminate\Http\Resources\Json\JsonResource;use App\Http\Resources\CityResource;use App\Http\Resources\StateResource;use App\Http\Resources\ServiceAreaResource;class RiderResource extends JsonResource{    /**     * Transform the resource into an array.     */    public function toArray(Request $request): array    {        return [            'id'        => $this->id,            'name'      => $this->name,            'photo'     => $this->photo,            'zip'       => $this->zip,            'city'      => new CityResource($this->city),            'state'     => new StateResource($this->state),            'country'   => $this->country,            'address'   => $this->address,            'phone'     => $this->phone,            'fax'       => $this->fax,            'zip'=>$this->zip,            'email'     => $this->email,            'vehicle_type' => $this->vehicle_type,            'location'  => $this->location,            'status'    => $this->status,            'balance'   => $this->balance,            'email_verify'=> $this->email_verify,                          'rider_type' => $this->rider_type,            'company_registration_document' => $this->company_registration_document                 ? asset('assets/images/companyregistrationdocument/'.$this->company_registration_document)                 : null,            'id_company_owner' => $this->id_company_owner                 ? asset('assets/images/companyownerid/'.$this->id_company_owner)                 : null,            'live_selfie_company' => $this->live_selfie_company                 ? asset('assets/images/liveselfiecompany/'.$this->live_selfie_company)                 : null,            'transport_license' => $this->transport_license                 ? asset('assets/images/transportlicense/'.$this->transport_license)                 : null,            'insurance_certificate_company' => $this->insurance_certificate_company                 ? asset('assets/images/insurancecertificatecompany/'.$this->insurance_certificate_company)                 : null,            'tin_company' => $this->tin_company,            // ✅ Individual specific fields            'vehicle_type_individual' => $this->vehicle_type_individual,            'tin_individual' => $this->tin_individual,            'driver_license_individual' => $this->driver_license_individual                 ? asset('assets/images/driverlicenseindividual/'.$this->driver_license_individual)                 : null,            'live_selfie_individual' => $this->live_selfie_individual                 ? asset('assets/images/liveselfieindividual/'.$this->live_selfie_individual)                 : null,            'vehicle_registration_certificate' => $this->vehicle_registration_certificate                 ? asset('assets/images/vehicleregistrationcertificate/'.$this->vehicle_registration_certificate)                 : null,            'insurance_certificate_individual' => $this->insurance_certificate_individual                 ? asset('assets/images/insurancecertificateindividual/'.$this->insurance_certificate_individual)                 : null,            'criminal_records' => $this->criminal_records                 ? asset('assets/images/criminalrecords/'.$this->criminal_records)                 : null,                        'submerchant_agreement' => $this->submerchant_agreement?asset('assets/images/submerchantagreementrider/'.$this->submerchant_agreement):null,            'service_areas' => ServiceAreaResource::collection($this->whenLoaded('serviceAreas')),            'national_id_front_image' => $this->national_id_front_image?asset('assets/images/rideridfront/'.$this->national_id_front_image):null,            'national_id_back_image'  => $this->national_id_back_image?asset('assets/images/rideridback/'.$this->national_id_back_image):null,            'license_image'           => $this->license_image?asset('assets/images/riderlicense/'.$this->license_image):null,            // Relations//            'orders'      => DeliveryRiderResource::collection($this->whenLoaded('orders')),            //'service_area' => new ServiceAreaResource($this->serviceArea),        ];    }}